// Helper types for proxy internal bookkeeping
type tQItem = (isWrite: bool, key: int);
type tReadWaiter = (opId: int, requester: machine, podId: int);
type tWriteEntry = (opId: int, requester: machine, podId: int, value: int);

// Helper events between CacheNode and StorageProxy
event eProxyReadReq: (opId: int, key: int, podId: int, requester: machine);
event eProxyWriteReq: (opId: int, key: int, value: int, podId: int, requester: machine);
event eProxyReadResp: (opId: int, key: int, value: int);
event eProxyWriteResp: (opId: int, key: int, success: bool, value: int);
event eProxyTick;

machine StorageProxy {
    var db: machine;

    // Global pending queue of storage-facing requests (opaque per-key; details in maps)
    var pendingQ: seq[tQItem];

    // Read coalescing
    var readWaiters: map[int, seq[tReadWaiter]]; // key -> list of (opId, requester, podId)
    var readQueued: set[int];                    // keys that have a queued-but-not-forwarded read
    var readInFlight: set[int];                  // keys with a forwarded read awaiting resp

    // Write sequencing: at most one in-flight write per key; a FIFO per key for queued writes
    var writeQueues: map[int, seq[tWriteEntry]]; // key -> queued writes
    var writeInFlight: map[int, tWriteEntry];    // key -> the single in-flight write

    start state Init {
        entry (p: (db: machine)) {
            db = p.db;
            // initialize collections
            pendingQ = default(seq[tQItem]);
            readWaiters = default(map[int, seq[tReadWaiter]]);
            readQueued = default(set[int]);
            readInFlight = default(set[int]);
            writeQueues = default(map[int, seq[tWriteEntry]]);
            writeInFlight = default(map[int, tWriteEntry]);
            send this, eProxyTick;
            goto Ready;
        }
    }

    state Ready {
        on eProxyReadReq do (req: (opId: int, key: int, podId: int, requester: machine)) {
            var waiters: seq[tReadWaiter];
            var w: tReadWaiter;
            var qi: tQItem;
            var pending: int;

            if (!(req.key in readWaiters)) {
                waiters = default(seq[tReadWaiter]);
                readWaiters[req.key] = waiters;
            }
            w = (opId = req.opId, requester = req.requester, podId = req.podId);
            readWaiters[req.key] += (sizeof(readWaiters[req.key]), w);

            if (!(req.key in readQueued) && !(req.key in readInFlight)) {
                // Enqueue a single storage-facing read for this key
                qi = (isWrite = false, key = req.key);
                pendingQ += (sizeof(pendingQ), qi);
                readQueued += (req.key);
                pending = sizeof(pendingQ);
                // Announce enqueue using the first waiter's podId
                announce eMonitorProxyEnqueue, (key = req.key, podId = readWaiters[req.key][0].podId, isWrite = false, pending = pending);
            }

            send this, eProxyTick;
        }

        on eProxyWriteReq do (req: (opId: int, key: int, value: int, podId: int, requester: machine)) {
            var q: seq[tWriteEntry];
            var e: tWriteEntry;
            var qi: tQItem;
            var pending: int;

            if (!(req.key in writeQueues)) {
                q = default(seq[tWriteEntry]);
                writeQueues[req.key] = q;
            }
            e = (opId = req.opId, requester = req.requester, podId = req.podId, value = req.value);
            writeQueues[req.key] += (sizeof(writeQueues[req.key]), e);

            // If nothing is in flight for this key and this is the first queued write, enqueue it
            if (!(req.key in writeInFlight) && sizeof(writeQueues[req.key]) == 1) {
                qi = (isWrite = true, key = req.key);
                pendingQ += (sizeof(pendingQ), qi);
                pending = sizeof(pendingQ);
                announce eMonitorProxyEnqueue, (key = req.key, podId = req.podId, isWrite = true, pending = pending);
            }

            send this, eProxyTick;
        }

        on eStorageReadResp do (resp: (key: int, value: int)) {
            var waiters: seq[tReadWaiter];
            var i: int;
            var w: tReadWaiter;

            if (resp.key in readInFlight) {
                // Deliver to all coalesced waiters
                waiters = readWaiters[resp.key];
                i = 0;
                while (i < sizeof(waiters)) {
                    w = waiters[i];
                    announce eMonitorProxyResponseDelivered, (key = resp.key, podId = w.podId, isWrite = false);
                    send w.requester, eProxyReadResp, (opId = w.opId, key = resp.key, value = resp.value);
                    i = i + 1;
                }
                // Cleanup
                readInFlight -= (resp.key);
                readWaiters -= (resp.key);
            }
            send this, eProxyTick;
        }

        on eStorageWriteResp do (resp: (key: int, success: bool, value: int)) {
            var infl: tWriteEntry;
            var nextHas: bool;
            var nextHead: tWriteEntry;
            var qi: tQItem;
            var pending: int;

            if (resp.key in writeInFlight) {
                infl = writeInFlight[resp.key];
                announce eMonitorProxyResponseDelivered, (key = resp.key, podId = infl.podId, isWrite = true);
                send infl.requester, eProxyWriteResp, (opId = infl.opId, key = resp.key, success = resp.success, value = resp.value);
                writeInFlight -= (resp.key);

                // If more writes are queued for this key, enqueue the next one now
                if (resp.key in writeQueues && sizeof(writeQueues[resp.key]) > 0) {
                    // Do not pop the head yet; it will be popped when forwarded
                    nextHead = writeQueues[resp.key][0];
                    qi = (isWrite = true, key = resp.key);
                    pendingQ += (sizeof(pendingQ), qi);
                    pending = sizeof(pendingQ);
                    announce eMonitorProxyEnqueue, (key = resp.key, podId = nextHead.podId, isWrite = true, pending = pending);
                }
            }
            send this, eProxyTick;
        }

        on eProxyTick do {
            var doHold: bool;
            var idx: int;
            var item: tQItem;
            var pod: int;
            var headW: tWriteEntry;

            if (sizeof(pendingQ) == 0) {
                // nothing to do
                return;
            }

            doHold = $;
            if (doHold) {
                announce eMonitorProxyHold, (pending = sizeof(pendingQ));
                // Keep pending requests queued; schedule another tick for future progress
                send this, eProxyTick;
                return;
            }

            idx = choose(sizeof(pendingQ));
            item = pendingQ[idx];
            pendingQ -= (idx);

            if (item.isWrite) {
                // Forward the head write for this key
                headW = writeQueues[item.key][0];
                // Move head into in-flight and pop from queue
                writeInFlight[item.key] = headW;
                writeQueues[item.key] -= (0);

                announce eMonitorProxyForward, (key = item.key, podId = headW.podId, isWrite = true, pending = sizeof(pendingQ));
                send db, eStorageWrite, (caller = this, key = item.key, value = headW.value, podId = headW.podId);
            } else {
                // Forward the read; mark queued->in-flight
                readQueued -= (item.key);
                readInFlight += (item.key);
                pod = readWaiters[item.key][0].podId;

                announce eMonitorProxyForward, (key = item.key, podId = pod, isWrite = false, pending = sizeof(pendingQ));
                send db, eStorageRead, (caller = this, key = item.key, podId = pod);
            }

            // Schedule another tick to model continuous network/interposition behavior
            send this, eProxyTick;
        }
    }
}

machine CacheNode {
    var proxy: machine;
    var podId: int;

    var nextOpId: int;

    // Read dedup per key within this node
    var readWaiters: map[int, seq[machine]]; // key -> list of clients
    var readOpIdByKey: map[int, int];        // key -> outstanding opId

    // Write tracking by opId
    var writeClientByOp: map[int, machine];  // opId -> client
    var writeKeyByOp: map[int, int];         // opId -> key

    // Optional local cache (not used to serve reads without storage to preserve LSI)
    var kv: map[int, int];

    start state Init {
        entry (p: (proxy: machine, podId: int)) {
            proxy = p.proxy;
            podId = p.podId;
            nextOpId = 1;
            readWaiters = default(map[int, seq[machine]]);
            readOpIdByKey = default(map[int, int]);
            writeClientByOp = default(map[int, machine]);
            writeKeyByOp = default(map[int, int]);
            kv = default(map[int, int]);
            goto Ready;
        }
    }

    state Ready {
        on eClientRead do (r: (client: machine, key: int)) {
            var waiters: seq[machine];
            var opId: int;

            // Coalesce per-key reads within this node to minimize proxy round trips
            if (r.key in readWaiters) {
                waiters = readWaiters[r.key];
                waiters += (sizeof(waiters), r.client);
                readWaiters[r.key] = waiters;
                return;
            }

            waiters = default(seq[machine]);
            waiters += (sizeof(waiters), r.client);
            readWaiters[r.key] = waiters;

            opId = nextOpId;
            nextOpId = nextOpId + 1;
            readOpIdByKey[r.key] = opId;

            // Always go through storage via proxy to preserve LSI
            announce eMonitorProxyRequestIssued, (key = r.key, podId = podId, isWrite = false);
            send proxy, eProxyReadReq, (opId = opId, key = r.key, podId = podId, requester = this);
        }

        on eProxyReadResp do (resp: (opId: int, key: int, value: int)) {
            var waiters: seq[machine];
            var i: int;
            var c: machine;

            if (resp.key in readWaiters) {
                waiters = readWaiters[resp.key];
                // update local cache with the committed value (for potential future use)
                kv[resp.key] = resp.value;

                i = 0;
                while (i < sizeof(waiters)) {
                    c = waiters[i];
                    send c, eReadResp, (key = resp.key, value = resp.value, fromCache = false);
                    i = i + 1;
                }
                readWaiters -= (resp.key);
                if (resp.key in readOpIdByKey) {
                    readOpIdByKey -= (resp.key);
                }
            }
        }

        on eClientWrite do (w: (client: machine, key: int, value: int)) {
            var opId: int;

            opId = nextOpId;
            nextOpId = nextOpId + 1;

            writeClientByOp[opId] = w.client;
            writeKeyByOp[opId] = w.key;

            announce eMonitorProxyRequestIssued, (key = w.key, podId = podId, isWrite = true);
            send proxy, eProxyWriteReq, (opId = opId, key = w.key, value = w.value, podId = podId, requester = this);
        }

        on eProxyWriteResp do (resp: (opId: int, key: int, success: bool, value: int)) {
            var c: machine;

            if (resp.opId in writeClientByOp) {
                c = writeClientByOp[resp.opId];
                // Update local cache with committed value on success
                if (resp.success) {
                    kv[resp.key] = resp.value;
                }
                send c, eWriteResp, (key = resp.key, success = resp.success);
                writeClientByOp -= (resp.opId);
                if (resp.opId in writeKeyByOp) {
                    writeKeyByOp -= (resp.opId);
                }
            }
        }
    }
}
